<?php

namespace App\Models;

use Illuminate\Database\Eloquent\Model;
use Illuminate\Database\Eloquent\Relations\BelongsTo;

/**
 * Class Evaluation
 * 
 * Represents an AI-generated evaluation for a specific student answer.
 * Provides automated scoring and feedback based on the answer content.
 * 
 * @package App\Models
 * 
 * @property int $ai_eval_id Unique identifier for the evaluation.
 * @property int $answer_id Foreign key linking to the DentAnswer model.
 * @property float $ai_score The score assigned by the AI.
 * @property string|null $ai_feedback Qualitative feedback generated by the AI.
 * @property \Illuminate\Support\Carbon $created_at
 * @property \Illuminate\Support\Carbon $updated_at
 * 
 * @property-read \App\Models\DentAnswer $answer The answer being evaluated.
 */
class Evaluation extends Model 
{
    /**
     * @var string The table associated with the model.
     */
    protected $table = 'ai_evaluations';

    /**
     * @var string The primary key for the model.
     */
    protected $primaryKey = 'ai_eval_id';

    /**
     * @var array The attributes that are mass assignable.
     */
    protected $fillable = ['answer_id', 'ai_score', 'ai_feedback'];

    /**
     * Get the student answer that this evaluation belongs to.
     * 
     * @return BelongsTo
     */
    public function answer() 
    { 
        return $this->belongsTo(DentAnswer::class, 'answer_id'); 
    }
}